        "title": "Delhi with Kids: The Ultimate Family-Friendly Guide to Attractions, Parks & Activities",
        "excerpt": "Travelling to Delhi with children? From interactive science museums and sprawling parks to child-friendly restaurants and safe transport tips — this is the complete parent's guide to exploring India's capital with kids of all ages.",
        "category": "guides",
        "categoryName": "Guides",
        "image": "assets/delhi-family-kids.webp",
        "author": "GetHotelStays Travel Team",
        "authorInitials": "GT",
        "authorLocation": "India Gate, Delhi",
        "date": "June 17, 2026",
        "readTime": "19 min read",
